code = """import json
# combine all fetched business records
records = []
for var in [var_call_S8hVipLrLCqBBXS3hZX41Dp1, var_call_3689M9zfp0NqNlUar3Z3hEDl, var_call_485jaWsDT8YiSFFwDFD86U5M, var_call_WatRLWG99zZPpJ6g0GPLOuAs, var_call_Rs8yzOl68WNKWyUjhhiwv3Cg, var_call_9UJZZUiFMCxeY7eWcv2FEHZK, var_call_7K1LlFPwpl3I178Yb9L8nUF5, var_call_nvsxIbcdggAIibMhi9ktcdCT]:
    records.extend(var)

# map business_id to attributes
bmap = {rec['business_id']: rec.get('attributes') for rec in records}

# business ids from reviews
review_refs = var_call_BwnslOpn6nux2h2CEeEJsuDl
review_bids = []
for r in review_refs:
    ref = r.get('business_ref')
    if ref and ref.startswith('businessref_'):
        review_bids.append('businessid_' + ref.split('_',1)[1])

# Count how many reviewed businesses offer either BusinessParking or BikeParking
count = 0
details = []
for bid in sorted(set(review_bids)):
    attrs = bmap.get(bid)
    has = False
    if attrs and isinstance(attrs, dict):
        # check BikeParking key
        bike = attrs.get('BikeParking')
        if bike is not None and bike != 'False':
            # treat any non-False as True (e.g., 'True')
            has = True
        # check BusinessParking key
        bp = attrs.get('BusinessParking')
        if bp is not None and bp != 'None' and bp != "None":
            # sometimes BusinessParking is a dict-string or 'None'
            # if it's a string containing 'False' for all entries, still counts as offered? 
            # We'll consider presence of BusinessParking and not equal to 'None' as offering some parking.
            if isinstance(bp, str):
                if 'False' in bp and 'True' not in bp:
                    # no True found, so may not offer; but some businesses have lot True etc.
                    # check for "True" or 'lot': True etc
                    if "True" in bp or "'lot': True" in bp or "lot': True" in bp or 'street': True in bp if False else False:
                        has = has or True
                    else:
                        # not offering according to this heuristic
                        pass
                else:
                    has = True
            else:
                # if it's dict, assume offering
                has = True
    # record
    if has:
        count += 1
        details.append(bid)

output = {"count": count, "businesses_with_parking": details}
print("__RESULT__:")
print(json.dumps(output))"""

